    public MainWindow(string? userName = null, string? userEmail = null)
    {
        InitializeComponent();
        _appInstance = this;
        DataContext = this;
        if (!string.IsNullOrEmpty(userName))
        {
            SidebarUserName.Text   = userName;
            SidebarAvatarText.Text = userName[0].ToString().ToUpper();
        }
        if (!string.IsNullOrEmpty(userEmail))
            SidebarUserRole.Text = userEmail;
        TxnGrid.ItemsSource           = _transactions;
        ItemsGrid.ItemsSource         = _items;
        DisbEntryGrid.ItemsSource     = _disbEntries;
        DisbGrid.ItemsSource          = _disbRecords;
        DisbEntryDetailGrid.ItemsSource = _disbDetailEntries;
        LoadSettings();
        // Apply proxy — non-dev machines always get proxy disabled (Fiddler tab is hidden,
        // and a stale localhost:8888 in settings.json would break all API calls)
        var proxyCfg = Services.SettingsService.Load();
        if (!_isDevMachine) proxyCfg.ProxyEnabled = false;
        Services.ProxyConfig.Apply(proxyCfg);
        InitHttpClient();
        InitSubscriptions();
        InitFiddler();
        InitEnvironments();
        InitPerformanceTester();
        InitWebhookTests();   // must run AFTER LoadSettings so EntityCustomBox is populated
        UpdateEnvironmentUI();
        AutoDetectLocalSettingsOnStartup();   // fill Local DB boxes from INI if not already saved
        // Apply restricted mode — full access only when signed in with dev email
        var startupSettings = Services.SettingsService.Load();
        bool restricted = !IsDevEmail(startupSettings.BqeLoginEmail);
        ApplyRestrictedMode(restricted);
        // Re-enforce user's saved HiddenTabs — ApplyRestrictedMode may have made hidden tabs visible
        ApplyTabVisibility(startupSettings.HiddenTabs ?? []);
        // Always start on Transaction Viewer (visible in both modes)
        _activeNavBtn = (System.Windows.Controls.Button)NavTxnViewer;
        MainTabControl.SelectedIndex = 0;
        // Refresh Overview KPIs whenever the transaction collection changes
        // (_suppressKpiRefresh batches bulk adds so we only recompute once at the end)
        _transactions.CollectionChanged += (_, _) => { if (!_suppressKpiRefresh) RefreshOverviewKpis(); };
        ApplyColumnChooserState(startupSettings);
        _isInitialized = true;   // all controls ready — event handlers may now call SaveSettings()
    }

    // ── Logout ───────────────────────────────────────────────────────────────

    private void LogoutBtn_Click(object sender, MouseButtonEventArgs e)
    {
        var confirm = WpfMessageBox.Show(
            $"Sign out of {SidebarUserName.Text}?\n\nUnsaved settings will be saved before signing out.",
            "Sign Out",
            System.Windows.MessageBoxButton.YesNo,
            System.Windows.MessageBoxImage.Question);

        if (confirm != System.Windows.MessageBoxResult.Yes) return;

        SaveSettings();

        // Clear any BQE Core session token on sign-out
        var s = SettingsService.Load();
        if (!string.IsNullOrEmpty(s.BqeJwtToken))
        {
            s.BqeJwtToken     = "";
            s.BqeLoggedInUser = "";
            SettingsService.Save(s);
            UpdateSidebarBqeBadge("", false);
        }

        // Show login window — must re-authenticate to continue
        var login = new LoginWindow();
        login.Owner = this;
        bool? result = login.ShowDialog();

        if (result == true)
        {
            // Update sidebar with the new signed-in user
            if (!string.IsNullOrEmpty(login.LoggedInName))
            {
                SidebarUserName.Text   = login.LoggedInName;
                SidebarAvatarText.Text = char.ToUpper(login.LoggedInName[0]).ToString();
            }
            if (!string.IsNullOrEmpty(login.LoggedInEmail))
                SidebarUserRole.Text = login.LoggedInEmail;

            SetStatus($"Signed in as {login.LoggedInName}.");
        }
        else
        {
            // User cancelled — close the app (no valid session)
            System.Windows.Application.Current.Shutdown();
        }
    }

