    public string DashLastUpdated   => $"Last updated: {DateTime.Now:MMM d, yyyy h:mm tt}";

    // ── Period / top-N filters ────────────────────────────────────────────────
    private int _dashPeriodDays = 30;   // 7 / 30 / 90 / 0 = All
    private int _dashTopN       = 5;    // 3 / 5 / 10 / 20

    public string DashPeriodLabel => _dashPeriodDays == 0 ? "All time" : $"Last {_dashPeriodDays} days";
    public string DashTopNLabel   => $"Top {_dashTopN} ▾";

    private IEnumerable<Models.Transaction> DashPeriodTxns
    {
        get
        {
            if (_dashPeriodDays == 0) return _transactions;
            var cutoff = DateTime.Now.Date.AddDays(-_dashPeriodDays);
            return _transactions.Where(t =>
                DateTime.TryParse(t.Created, out var d) && d.Date >= cutoff);
        }
    }

    // Recent transactions (most recent first, period-filtered)
    public IEnumerable<Models.Transaction> DashRecentTransactions
        => DashPeriodTxns.OrderByDescending(t => t.Created).Take(5);

    // Top merchants by approved volume (period + top-N filtered)
    public IEnumerable<(string Name, string Volume, int Count)> DashTopMerchants
        => DashPeriodTxns
           .GroupBy(t => t.Merchant ?? "Unknown")
           .OrderByDescending(g => g.Sum(t => t.ApprovedDollars))
           .Take(_dashTopN)
           .Select(g => (
               Name: g.FirstOrDefault()?.MerchantDisplayName ?? g.Key,
               Volume: g.Sum(t => t.ApprovedDollars).ToString("C2", new System.Globalization.CultureInfo("en-US")),
               Count: g.Count()
           ));

    // Additional helpers
    public int    DashTotalMerchants   => _merchants.Count;
    public int    DashBankCount        => _transactions.Count(t => !t.IsAch && t.Type == 3);
    private string PctByCount(int count) { var t = _transactions.Count; return t == 0 ? "(0.0%)" : $"({count * 100.0 / t:F1}%)"; }
    public string DashCardPct          => PctByCount(OverviewCardCount);
    public string DashAchMethodPct     => PctByCount(OverviewAchCount);
    public string DashBankPct          => PctByCount(DashBankCount);

    // ── API Tools KPIs (live from collections + request log) ─────────────────
    public int    OverviewApiCount        => _collections.Sum(c => c.Requests.Count);
    public int    OverviewCollectionCount => _collections.Count;
    public int    OverviewRecentCount     => Services.RequestLogService.Load().Count;
    public string OverviewApiCountFmt     => OverviewApiCount.ToString("N0");

    // Per-collection breakdown for the mini table (top 6 by size)
    public IEnumerable<(string Name, int Count)> OverviewTopCollections
        => _collections
           .OrderByDescending(c => c.Requests.Count)
           .Take(6)
           .Select(c => (c.Name, c.Requests.Count));

    private void RefreshOverviewKpis()
    {
        OnPropertyChanged(nameof(DashPeriodLabel));
        OnPropertyChanged(nameof(DashTopNLabel));
        OnPropertyChanged(nameof(OverviewTxnCount));
        OnPropertyChanged(nameof(OverviewApproved));
        OnPropertyChanged(nameof(OverviewAchCount));
        OnPropertyChanged(nameof(OverviewCardCount));
        OnPropertyChanged(nameof(OverviewFailedCount));
        OnPropertyChanged(nameof(OverviewReturnedCount));
        OnPropertyChanged(nameof(OverviewSettledCount));
        OnPropertyChanged(nameof(OverviewSettledAmount));
        OnPropertyChanged(nameof(OverviewPendingCount));
        OnPropertyChanged(nameof(OverviewCapturedCount));
        OnPropertyChanged(nameof(OverviewAvgAmount));
        OnPropertyChanged(nameof(OverviewDisbursedCount));
        OnPropertyChanged(nameof(OverviewAchPct));
        OnPropertyChanged(nameof(OverviewCardPct));
        // Dashboard KPIs
        OnPropertyChanged(nameof(DashTotalVolume));
        OnPropertyChanged(nameof(DashSettlementRate));
        OnPropertyChanged(nameof(DashActiveMerchants));
        OnPropertyChanged(nameof(DashApprovedCount));
        OnPropertyChanged(nameof(DashCapturedCount));
        OnPropertyChanged(nameof(DashDeclinedCount));
        OnPropertyChanged(nameof(DashErrorCount));
        OnPropertyChanged(nameof(DashSettledAchCount));
        OnPropertyChanged(nameof(DashReturnedCount));
