        base.OnClosing(e);
    }

    private void SaveSettings()
    {
        if (!_isInitialized) return;   // called before controls exist — skip

        // Load existing settings first so we preserve fields not managed by the UI
        // (e.g. OAuth client IDs stored directly in settings.json)
        var existing = SettingsService.Load();

        SettingsService.Save(new AppSettings
        {
            // ── OAuth credentials — carry forward from file, never overwrite ──
            GoogleClientId     = existing.GoogleClientId,
            GoogleClientSecret = existing.GoogleClientSecret,
            MicrosoftClientId  = existing.MicrosoftClientId,
            AppleClientId      = existing.AppleClientId,
            IsSandbox        = IsSandbox,
            SandboxApiKey    = SandboxApiKeyBox.Password,
            ProductionApiKey = ProductionApiKeyBox.Password,
            UserEmail        = UserEmailBox.Text.Trim(),
            SearchLimit      = SearchLimitBox.Text.Trim(),
            LatestCountIndex = LatestCountBox.SelectedIndex,
            TransactionIds   = TxnIdsBox.Text.Trim(),
            DisbursementId    = DisbursementIdBox.Text.Trim(),
            DisbursementLimit = DisbLimitBox.Text.Trim(),
            WebhookEnvIndex  = WebhookEnvBox.SelectedIndex,
            WebhookUrl                     = WebhookUrlBox.Text.Trim(),
            LocalHostDbConnectionString    = LocalHostDbBox.Text.Trim(),
            StagingHostDbConnectionString  = StagingHostDbBox.Text.Trim(),
            SprintHostDbConnectionString   = SprintHostDbBox.Text.Trim(),
            CoreAccountEmail               = CoreAccountEmailBox.Text.Trim(),
            LocalMainDbConnectionString    = LocalMainDbBox.Text.Trim(),
            StagingMainDbConnectionString  = StagingMainDbBox.Text.Trim(),
            SprintMainDbConnectionString   = SprintMainDbBox.Text.Trim(),
            EntityCustomField = EntityCustomBox.Text.Trim(),
            AchTxnId         = _perTypeTxnId.GetValueOrDefault(0, AchTxnIdBox.Text.Trim()),
            AchAmount        = _perTypeAmount.GetValueOrDefault(0, AchAmountBox.Text.Trim()),
            RefundTxnId      = _perTypeTxnId.GetValueOrDefault(1, ""),
            RefundAmount     = _perTypeAmount.GetValueOrDefault(1, ""),
            CcRefundTxnId    = _perTypeTxnId.GetValueOrDefault(2, ""),
            CcRefundAmount   = _perTypeAmount.GetValueOrDefault(2, ""),
            CcReturnTxnId    = _perTypeTxnId.GetValueOrDefault(3, ""),
            CcReturnAmount   = _perTypeAmount.GetValueOrDefault(3, ""),
            WebhookTypeIndex = WebhookTypeBox.SelectedIndex,
            KpiVisible          = KpiGrid.Visibility == Visibility.Visible,
            EmailSectionCollapsed = EmailSectionContent.Visibility  == Visibility.Collapsed,
            TxnSectionCollapsed   = TxnSectionContent.Visibility    == Visibility.Collapsed,
            DisbSectionCollapsed  = DisbSectionContent.Visibility   == Visibility.Collapsed,
            EmailSectionPinned = EmailPinBtn.Tag?.ToString() == "pinned",
            TxnSectionPinned   = TxnPinBtn.Tag?.ToString()   == "pinned",
            DisbSectionPinned  = DisbPinBtn.Tag?.ToString()  == "pinned",
            SearchPanelCollapsed  = SearchSectionsPanel.Visibility  == Visibility.Collapsed,
            WebhookConfigExpanded = WebhookDateFilterPanel.Visibility == Visibility.Visible,
            IsDarkMode         = _isDarkMode,
            IsRestrictedMode   = RestrictedModeChk.IsChecked == true,
            HiddenTabs         = Enumerable.Range(0, 20)
                                    .Where(t => !PinnedTabs.Contains(t) && GetNavButton(t)?.Visibility == Visibility.Collapsed)
                                    .ToList(),
            WindowWidth      = Width,
            WindowHeight     = Height,
            WindowLeft       = Left,
            WindowTop        = Top,
            // Fiddler / proxy
            ProxyEnabled     = FiddlerTabProxyEnabledChk.IsChecked == true,
            ProxyUrl         = FiddlerTabProxyUrlBox.Text.Trim(),
            ProxyBypassLocal = FiddlerTabBypassLocalChk.IsChecked == true,
            // BQE Core account
            BqeCoreBaseUrl   = BqeCoreUrlBox.Text.Trim(),
            BqeLoginEmail    = BqeEmailBox.Text.Trim(),
            BqeLoginPassword = BqePasswordBox.Password,  // saved so user doesn't retype each session
            BqeJwtToken      = existing.BqeJwtToken,     // preserved — only updated by sign-in/out
            BqeLoggedInUser  = existing.BqeLoggedInUser,
            // Core DB Utility
            CoreHostServer   = HostServerBox.Text.Trim(),
            CoreHostUser     = HostUserBox.Text.Trim(),
            CoreHostPassword = HostPasswordBox.Password,
            CoreHostDatabase = HostDatabaseBox.Text.Trim(),
            CoreDbServer     = CoreServerBox.Text.Trim(),
            CoreDbUser       = CoreUserBox.Text.Trim(),
            CoreDbPassword   = CorePasswordBox.Password,
        });

        // Keep PaymentServiceManager .cs line 2359 in sync with entity custom
        PatchPaymentServiceManagerCustom(EntityCustomBox.Text.Trim());
    }

    // ── PaymentServiceManager custom-field patcher ───────────────────────────

    private static readonly string PaymentServiceManagerPath =
        @"C:\Projects\Core\BQECoreHost\Applications\BQECoreHostBusinessLogic\PaymentServiceManager .cs";

    /// <summary>
    /// Patches line 2359 of PaymentServiceManager .cs so the hardcoded custom override
    /// matches whatever EntityCustom is set to in this app.
    /// </summary>
    private static void PatchPaymentServiceManagerCustom(string custom)
    {
        if (string.IsNullOrWhiteSpace(custom)) return;
        if (!System.IO.File.Exists(PaymentServiceManagerPath)) return;

        var lines = System.IO.File.ReadAllLines(PaymentServiceManagerPath);

        // Search for the launcher-fallback line dynamically — matches "custom = "GUID,GUID";" lines.
        // Always takes the LAST match, which is the OnChargeReimbursement fallback slot.
        var uuidPair = new System.Text.RegularExpressions.Regex(
            @"[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12},[0-9a-fA-F]{8}");
        int targetIndex = -1;
        for (int i = 0; i < lines.Length; i++)
        {
            var trimmed = lines[i].TrimStart();
            if ((trimmed.StartsWith("custom =", StringComparison.Ordinal) ||
                 trimmed.StartsWith("//custom =", StringComparison.Ordinal)) &&
                uuidPair.IsMatch(trimmed))
                targetIndex = i;
        }
        if (targetIndex < 0) return;

        var original     = lines[targetIndex];
        var indent       = original.Length - original.TrimStart().Length;
        var leadingSpaces = original[..indent];

        lines[targetIndex] = $"{leadingSpaces}custom = \"{custom}\";";
        System.IO.File.WriteAllLines(PaymentServiceManagerPath, lines);
    }

