    // ── Fetch transactions ────────────────────────────────────────────────────

    /// <summary>
    /// Resolves the merchant filter box to a Payrix merchant ID.
    /// Accepts: merchant name, DBA, email address, merchant ID (t1_mer_/p1_mer_), or entity ID.
    /// Returns null if empty. Sets MerchantResolvedLabel with the resolved name + ID.
    /// </summary>
    private async Task<string?> ResolveMerchantIdAsync(PayrixService service)
    {
        var query = TxnMerchantFilterBox.Text.Trim();
        if (string.IsNullOrEmpty(query))
        {
            MerchantResolvedLabel.Text = "—";
            return null;
        }

        // Direct merchant ID — no lookup needed
        if (query.StartsWith("t1_mer_", StringComparison.OrdinalIgnoreCase) ||
            query.StartsWith("p1_mer_", StringComparison.OrdinalIgnoreCase))
        {
            MerchantResolvedLabel.Text = $"✓ {query}";
            return query;
        }

        // Anything else: name, DBA, email, entity ID — search Payrix
        MerchantResolvedLabel.Text = "🔍 Searching…";
        var (merchants, _, err) = await service.SearchMerchantsAsync(query);
        if (err != null || merchants.Count == 0)
        {
            MerchantResolvedLabel.Text = $"⚠ Not found: {query}";
            return null;
        }

        var m = merchants[0];
        // Build a label showing what matched
        var matchedVia = query.Contains('@') ? $"email: {query}"
                       : !string.IsNullOrWhiteSpace(m.Dba) ? m.Dba
                       : m.Name;
        MerchantResolvedLabel.Text = $"✓ {m.Name}  [{m.Id}]";
        MerchantResolvedLabel.ToolTip = $"Matched via: {matchedVia}\nMerchant ID: {m.Id}\nEntity: {m.Entity}";
        return m.Id;
    }

    private void TxnClearDateBtn_Click(object sender, RoutedEventArgs e)
    {
        TxnFromDatePicker.SelectedDate = null;
        TxnToDatePicker.SelectedDate   = null;
        ApplyLocalDateFilter();
    }

    private void TxnDatePicker_SelectedDateChanged(object sender, System.Windows.Controls.SelectionChangedEventArgs e)
        => ApplyLocalDateFilter();

    private void ApplyLocalDateFilter()
    {
        if (_allFetchedTransactions.Count == 0) return;

        var from = TxnFromDatePicker.SelectedDate;
        var to   = TxnToDatePicker.SelectedDate;

        var filtered = _allFetchedTransactions
            .Where(t => (!from.HasValue || (DateTime.TryParse(t.Created, out var fd) && fd.Date >= from.Value.Date))
                     && (!to.HasValue   || (DateTime.TryParse(t.Created, out var td) && td.Date <= to.Value.Date)))
            .OrderByDescending(t => t.Created)
            .ToList();

        _transactions.Clear();
        foreach (var t in filtered)
            _transactions.Add(t);

        UpdateSummary();
    }

    private void SortTransactionsByCreated()
    {
        var sorted = _transactions.OrderByDescending(t => t.Created).ToList();
        _transactions.Clear();
        foreach (var t in sorted)
            _transactions.Add(t);
    }

    private void TxnColChooserBtn_Toggled(object sender, RoutedEventArgs e)
    {
        if (TxnColChooserBtn.IsChecked == true)
        {
            BuildColChooser();
            TxnColChooserPopup.IsOpen = true;
        }
        else
        {
            TxnColChooserPopup.IsOpen = false;
        }
    }

    private void TxnColChooserPopup_Closed(object sender, EventArgs e)
    {
        TxnColChooserBtn.IsChecked = false;
    }

    private void BuildColChooser()
    {
        TxnColChooserPanel.Children.Clear();
        foreach (var col in TxnGrid.Columns)
        {
            var header = col.Header?.ToString();
            if (string.IsNullOrWhiteSpace(header) || header == "🔗") continue;

            var cb = new System.Windows.Controls.CheckBox
            {
                Content    = header,
                IsChecked  = col.Visibility == Visibility.Visible,
                Margin     = new Thickness(4, 3, 4, 3),
                FontSize   = 12,
                Foreground = (System.Windows.Media.Brush)FindResource("PrimaryText"),
                Tag        = col
            };
            cb.Checked   += ColChooser_CheckChanged;
            cb.Unchecked += ColChooser_CheckChanged;
            TxnColChooserPanel.Children.Add(cb);
        }
    }

    private void ColChooser_CheckChanged(object sender, RoutedEventArgs e)
    {
        if (sender is System.Windows.Controls.CheckBox cb &&
            cb.Tag is System.Windows.Controls.DataGridColumn col)
        {
            col.Visibility = cb.IsChecked == true ? Visibility.Visible : Visibility.Collapsed;
        }
    }

    private void TxnSortCombo_Changed(object sender, RoutedEventArgs e)
    {
        if (TxnSortCombo is null || TxnSortDirBtn is null || _transactions is null) return;
        var field = (TxnSortCombo.SelectedItem as System.Windows.Controls.ComboBoxItem)?.Tag?.ToString();
        if (string.IsNullOrEmpty(field)) return;

        var direction = TxnSortDirBtn.IsChecked == true
            ? System.ComponentModel.ListSortDirection.Ascending
            : System.ComponentModel.ListSortDirection.Descending;

        var view = System.Windows.Data.CollectionViewSource.GetDefaultView(_transactions);
        view.SortDescriptions.Clear();
        view.SortDescriptions.Add(new System.ComponentModel.SortDescription(field, direction));
    }

    private async void FetchBtn_Click(object sender, RoutedEventArgs e)
    {
        SetBusy(true);
        var apiKey = IsSandbox ? SandboxApiKeyBox.Password.Trim() : ProductionApiKeyBox.Password.Trim();
        var envLabel = IsSandbox ? "Sandbox" : "Production";

        if (string.IsNullOrEmpty(apiKey))
        {
            SetStatus($"Please enter a {envLabel} API key.", error: true);
            return;
        }

        var ids = TxnIdsBox.Text
            .Split([',', '\n', '\r'], StringSplitOptions.RemoveEmptyEntries)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToArray();

        if (ids.Length == 0)
        {
            SetStatus("Please enter at least one transaction ID.", error: true);
            return;
        }

        await FetchTransactionsByIdsAsync(ids);
    }

    private async Task FetchTransactionsByIdsAsync(string[] ids)
    {
        var apiKey = IsSandbox ? SandboxApiKeyBox.Password.Trim() : ProductionApiKeyBox.Password.Trim();
        var envLabel = IsSandbox ? "Sandbox" : "Production";

        FetchBtn.IsEnabled = false;
        FetchLatestBtn.IsEnabled = false;
        SetExportEnabled(false);
        SetStatus($"[{envLabel}] Fetching {ids.Length} transaction(s)...");
        SetConnectionStatus(false);
        SetBusyCount(ids.Length);

        _transactions.Clear();
        _items.Clear();
        _disbEntries.Clear();
        _rawJsons.Clear();
        _selectedTransaction = null;
        ClearRawJson();
        UpdateSummary();
        ShowItemsPlaceholder(true);

        try
        {
            var environment = IsSandbox ? PayrixEnvironment.Sandbox : PayrixEnvironment.Production;
            var service = new PayrixService(apiKey, environment);
            int success = 0, failed = 0;
            var _fetchLock = new object();
            var _sem       = new SemaphoreSlim(5, 5);

            SetStatus($"[{envLabel}] Fetching {ids.Length} transaction(s) in parallel…");
            await Task.WhenAll(ids.Select(async id =>
            {
                await _sem.WaitAsync();
                try
                {
                    var (txn, rawJson, error) = await service.GetTransactionAsync(id);
                    if (error is not null || txn is null)
                    {
                        lock (_fetchLock) failed++;
                        return;
                    }
                    await EnrichTransactionAsync(service, txn, envLabel, bulkMode: true);
                    // Add to grid immediately so it appears as soon as it's ready
                    await Dispatcher.InvokeAsync(() =>
                    {
                        _suppressKpiRefresh = true;
                        _transactions.Add(txn);
                        _rawJsons.Add(rawJson);
                        _suppressKpiRefresh = false;
                    });
                    lock (_fetchLock) success++;
                }
                catch { lock (_fetchLock) { failed++; } }
                finally { _sem.Release(); IncrementBusyProgress(); }
            }));

            SortTransactionsByCreated();
            RefreshOverviewKpis();

            if (_rawJsons.Count > 0)
            {
                SetRawJson(_rawJsons.Count == 1
                    ? PrettyPrint(_rawJsons[0])
                    : "[" + Environment.NewLine +
                      string.Join("," + Environment.NewLine, _rawJsons.Select(PrettyPrint)) +
                      Environment.NewLine + "]");
            }

            UpdateSummary();
            SetConnectionStatus(success > 0);

            SetStatus(
                failed == 0
                    ? $"[{envLabel}] Fetched {success} transaction(s) successfully."
                    : $"[{envLabel}] Fetched {success} OK, {failed} failed.",
                error: failed > 0 && success == 0);

            if (success > 0)
                ShowToast($"All {success} transaction(s) fetched — enjoy! 🎉");

            SetExportEnabled(_transactions.Count > 0);

            if (_transactions.Count > 0)
            {
                LoadAllItems();
            }
        }
        catch (Exception ex)
        {
            SetStatus($"Unexpected error: {ex.Message}", error: true);
            WpfMessageBox.Show($"Error during fetch:\n\n{ex.Message}\n\n{ex.InnerException?.Message}",
                "Fetch Error", MessageBoxButton.OK, MessageBoxImage.Error);
        }
        finally
        {
            SetBusy(false);
            FetchBtn.IsEnabled = true;
            FetchLatestBtn.IsEnabled = true;
        }
    }

    // ── Fetch latest IDs by email ─────────────────────────────────────────────

    private async void SearchEmailBtn_Click(object sender, RoutedEventArgs e)
    {
        SetBusy(true);
        var apiKey = IsSandbox ? SandboxApiKeyBox.Password.Trim() : ProductionApiKeyBox.Password.Trim();
        var envLabel = IsSandbox ? "Sandbox" : "Production";

        if (string.IsNullOrEmpty(apiKey))
        {
            SetStatus($"Please enter a {envLabel} API key.", error: true);
            return;
        }

        var email           = UserEmailBox.Text.Trim();
        var hasEmail        = !string.IsNullOrEmpty(email);
        var merchantQuery   = TxnMerchantFilterBox.Text.Trim();
        var hasMerchantQuery = !string.IsNullOrEmpty(merchantQuery);
        var limit = int.TryParse(SearchLimitBox.Text.Trim(), out var l) && l > 0 ? l : 20;

        SearchEmailBtn.IsEnabled = false;
        FetchBtn.IsEnabled = false;
        FetchLatestBtn.IsEnabled = false;
        SetExportEnabled(false);
        SetConnectionStatus(false);

        _transactions.Clear();
        _allFetchedTransactions.Clear();
        _items.Clear();
        _disbEntries.Clear();
        _rawJsons.Clear();
        _selectedTransaction = null;
        ClearRawJson();
        UpdateSummary();
        ShowItemsPlaceholder(true);

        try
        {
            var environment = IsSandbox ? PayrixEnvironment.Sandbox : PayrixEnvironment.Production;
            var service = new PayrixService(apiKey, environment);

            SetBusyText("🌐  Fetching from Payrix API…");
            var fromDate   = TxnFromDatePicker.SelectedDate;
            var toDate     = TxnToDatePicker.SelectedDate;
            var merchantId = await ResolveMerchantIdAsync(service);

            // Block if merchant name was typed but couldn't be resolved
            if (hasMerchantQuery && merchantId == null)
            {
                SetStatus($"⚠ Merchant '{merchantQuery}' not found — search cancelled.", error: true);
                return;
            }

            // Priority: merchant > email > all
            // When merchant is given, email is ignored (merchant filter is sufficient)
            // When only email is given, filter by email
            // When neither, fetch all within limit
            string? effectiveEmail = merchantId != null ? null : (hasEmail ? email : null);

            var statusMsg = (merchantId != null, hasEmail) switch
            {
                (true,  _)     => $"[{envLabel}] Fetching up to {limit} transaction(s) for merchant…",
                (false, true)  => $"[{envLabel}] Searching transactions for {email}…",
                _              => $"[{envLabel}] Fetching latest {limit} transaction(s)…"
            };
            SetStatus(statusMsg);

            var fetchAll = service.SearchByEmailAsync(effectiveEmail, limit, fromDate, toDate, merchantId);
            var fetchAch = service.SearchByPaymentCategoryAsync(effectiveEmail, "ach", limit, fromDate, toDate, merchantId);
            await Task.WhenAll(fetchAll, fetchAch);

            var (allTxns, rawJson, error) = fetchAll.Result;
            var (achTxns, _, _)           = fetchAch.Result;

            // Always show raw response so the user can inspect it
            _rawJsons.Add(rawJson);
            SetRawJson(PrettyPrint(rawJson));

            if (error is not null && allTxns.Count == 0 && achTxns.Count == 0)
            {
                SetStatus($"Search error: {error}", error: true);
                return;
            }

            var merged = allTxns
                .Concat(achTxns)
                .GroupBy(t => t.Id)
                .Select(g => g.First())
                .OrderByDescending(t => t.Created)
                .Take(limit)
                .ToList();

            if (merged.Count == 0)
            {
                var noResultMsg = (merchantId != null, hasEmail) switch
                {
                    (true,  _)     => $"[{envLabel}] No transactions found for this merchant.",
                    (false, true)  => $"[{envLabel}] No transactions found for {email}. Check Raw JSON tab for API response.",
                    _              => $"[{envLabel}] No transactions found. Check Raw JSON tab for API response."
                };
                SetStatus(noResultMsg, error: true);
                return;
            }

            // ── Phase 2: enrich in parallel — counter visible the whole time ────
            SetStatus($"[{envLabel}] Loading details for {merged.Count} transaction(s)…");
            SetBusyCount(merged.Count);
            await Task.WhenAll(merged.Select(async txn =>
            {
                await EnrichTransactionAsync(service, txn, envLabel, bulkMode: true);
                await Dispatcher.InvokeAsync(() =>
                {
                    _suppressKpiRefresh = true;
                    _allFetchedTransactions.Add(txn);
                    _suppressKpiRefresh = false;
                });
                IncrementBusyProgress();
            }));

            // Populate _transactions via date filter (or all if no dates set)
            ApplyLocalDateFilter();
            RefreshOverviewKpis();

            UpdateSummary();
            SetConnectionStatus(true);

            var achCount = _transactions.Count(t => t.IsAch);
            var foundMsg = (merchantId != null, hasEmail) switch
            {
                (true,  _)     => $"[{envLabel}] Found {_transactions.Count} transaction(s) for merchant",
                (false, true)  => $"[{envLabel}] Found {_transactions.Count} transaction(s) for {email}",
                _              => $"[{envLabel}] Fetched {_transactions.Count} latest transaction(s)"
            };
            SetStatus(foundMsg + (achCount > 0 ? $" (including {achCount} ACH)." : "."));

            ShowToast($"All {_transactions.Count} transaction(s) fetched — enjoy! 🎉");

            SetExportEnabled(true);

            if (_transactions.Count > 0)
            {
                LoadAllItems();
            }
        }
        catch (Exception ex)
        {
            SetStatus($"Search failed: {ex.Message}", error: true);
            WpfMessageBox.Show($"Error searching transactions:\n\n{ex.Message}\n\n{ex.InnerException?.Message}",
                "Search Error", MessageBoxButton.OK, MessageBoxImage.Error);
        }
        finally
        {
            SetBusy(false);
            SearchEmailBtn.IsEnabled = true;
            FetchBtn.IsEnabled = true;
            FetchLatestBtn.IsEnabled = true;
        }
    }

    private async void FetchLatestBtn_Click(object sender, RoutedEventArgs e)
    {
        SetBusy(true);
        var apiKey = IsSandbox ? SandboxApiKeyBox.Password.Trim() : ProductionApiKeyBox.Password.Trim();
        var envLabel = IsSandbox ? "Sandbox" : "Production";

        if (string.IsNullOrEmpty(apiKey))
        {
            SetStatus($"Please enter a {envLabel} API key.", error: true);
            return;
        }

        var email         = UserEmailBox.Text.Trim();
        var hasEmail      = !string.IsNullOrEmpty(email);
        var merchantQuery = TxnMerchantFilterBox.Text.Trim();
        var hasMerchantQuery = !string.IsNullOrEmpty(merchantQuery);

        var countText = (LatestCountBox.SelectedItem as System.Windows.Controls.ComboBoxItem)?.Content?.ToString() ?? "1";
        var count = int.TryParse(countText, out var n) && n > 0 ? n : 1;

        FetchLatestBtn.IsEnabled = false;
        FetchBtn.IsEnabled = false;
        SearchEmailBtn.IsEnabled = false;
        SetExportEnabled(false);
        SetConnectionStatus(false);

        _transactions.Clear();
        _allFetchedTransactions.Clear();
        _items.Clear();
        _disbEntries.Clear();
        _rawJsons.Clear();
        _selectedTransaction = null;
        ClearRawJson();
        UpdateSummary();
        ShowItemsPlaceholder(true);

        try
        {
            var environment = IsSandbox ? PayrixEnvironment.Sandbox : PayrixEnvironment.Production;
            var service = new PayrixService(apiKey, environment);

            // ── Phase 1: resolve merchant + fetch ────────────────────────────────
            SetBusyText("🌐  Fetching from Payrix API…");
            var fromDate   = TxnFromDatePicker.SelectedDate;
            var toDate     = TxnToDatePicker.SelectedDate;
            var merchantId = await ResolveMerchantIdAsync(service);

            // Block if merchant name was typed but not found
            if (hasMerchantQuery && merchantId == null)
            {
                SetStatus($"⚠ Merchant '{merchantQuery}' not found — fetch cancelled.", error: true);
                return;
            }

            // Priority: merchant > email > all
            // Merchant given → use merchant, ignore email
            // No merchant + email → use email
            // Neither → fetch all within limit
            var effectiveEmail = merchantId != null ? null : (hasEmail ? email : null);

            SetStatus((merchantId != null, hasEmail) switch
            {
                (true,  _)     => $"[{envLabel}] Fetching latest {count} transaction(s) for merchant…",
                (false, true)  => $"[{envLabel}] Fetching latest {count} transaction(s) for {email}…",
                _              => $"[{envLabel}] Fetching latest {count} transaction(s)…"
            });

            var fetchAll = service.SearchByEmailAsync(effectiveEmail, count, fromDate, toDate, merchantId);
            var fetchAch = service.SearchByPaymentCategoryAsync(effectiveEmail, "ach", count, fromDate, toDate, merchantId);
            await Task.WhenAll(fetchAll, fetchAch);

            var (allTxns, rawJson, allError) = fetchAll.Result;
            var (achTxns, _, _)              = fetchAch.Result;

            // Merge: union by ID, apply date filter, sort newest-first, take requested count
            var merged = allTxns
                .Concat(achTxns)
                .GroupBy(t => t.Id)
                .Select(g => g.First())
                .OrderByDescending(t => t.Created)
                .Take(count)
                .ToList();

            if (allError is not null && merged.Count == 0)
            {
                SetStatus($"Error: {allError}", error: true);
                return;
            }

            if (merged.Count == 0)
            {
                var noMsg = (merchantId != null, hasEmail) switch
                {
                    (true,  _)     => $"[{envLabel}] No transactions found for this merchant.",
                    (false, true)  => $"[{envLabel}] No transactions found for '{email}'. Check the email or switch environment.",
                    _              => $"[{envLabel}] No transactions found. Check API key or switch environment."
                };
                SetStatus(noMsg, error: true);
                return;
            }

            // ── Phase 2: enrich in parallel with live counter ────────────────────
            SetStatus($"[{envLabel}] Loading details for {merged.Count} transaction(s)…");
            SetBusyCount(merged.Count);
            await Task.WhenAll(merged.Select(async txn =>
            {
                await EnrichTransactionAsync(service, txn, envLabel, bulkMode: true);
                await Dispatcher.InvokeAsync(() =>
                {
                    _suppressKpiRefresh = true;
                    _allFetchedTransactions.Add(txn);
                    _suppressKpiRefresh = false;
                });
                IncrementBusyProgress();
            }));

            // Populate _transactions via date filter (or all if no dates set)
            ApplyLocalDateFilter();
            RefreshOverviewKpis();

            TxnIdsBox.Text = string.Join(", ", merged.Select(t => t.Id).Where(id => id is not null));

            _rawJsons.Add(rawJson);
            SetRawJson(PrettyPrint(rawJson));

            UpdateSummary();
            SetConnectionStatus(true);

            var achCount = _transactions.Count(t => t.IsAch);
            var okMsg = (merchantId != null, hasEmail) switch
            {
                (true,  _)     => $"[{envLabel}] Loaded {_transactions.Count} transaction(s) for merchant",
                (false, true)  => $"[{envLabel}] Loaded {_transactions.Count} transaction(s) for {email}",
                _              => $"[{envLabel}] Loaded latest {_transactions.Count} transaction(s)"
            };
            SetStatus(okMsg + (achCount > 0 ? $" (including {achCount} ACH)." : "."));

            ShowToast($"All {merged.Count} transaction(s) fetched — enjoy! 🎉");

            SetExportEnabled(true);

            if (_transactions.Count > 0)
            {
                LoadAllItems();
            }
        }
        catch (Exception ex)
        {
            SetStatus($"Fetch Latest failed: {ex.Message}", error: true);
            WpfMessageBox.Show($"Error loading transactions:\n\n{ex.Message}\n\n{ex.InnerException?.Message}",
                "Load Error", MessageBoxButton.OK, MessageBoxImage.Error);
        }
        finally
        {
            SetBusy(false);
            FetchLatestBtn.IsEnabled = true;
            FetchBtn.IsEnabled = true;
            SearchEmailBtn.IsEnabled = true;
        }
    }

    // ── Fetch ACH / Credit Card quick-filter ─────────────────────────────────

    private void FetchAchBtn_Click(object sender, RoutedEventArgs e)
        => _ = FetchByPaymentCategoryAsync("ach");

    private void FetchCardBtn_Click(object sender, RoutedEventArgs e)
        => _ = FetchByPaymentCategoryAsync("card");

    private async Task FetchByPaymentCategoryAsync(string category)
    {
        var apiKey   = IsSandbox ? SandboxApiKeyBox.Password.Trim() : ProductionApiKeyBox.Password.Trim();
        var envLabel = IsSandbox ? "Sandbox" : "Production";

        if (string.IsNullOrEmpty(apiKey))
        {
            SetStatus("Please enter an API key.", error: true);
            return;
        }

        var email = UserEmailBox.Text.Trim();
        var countText = (LatestCountBox.SelectedItem as System.Windows.Controls.ComboBoxItem)?.Content?.ToString() ?? "20";
        var limit = int.TryParse(countText, out var l) && l > 0 ? l : 20;
        var label = category == "ach" ? "ACH/eCheck" : "Credit Card";

        SetBusy(true);
        FetchAchBtn.IsEnabled  = false;
        FetchCardBtn.IsEnabled = false;
        FetchBtn.IsEnabled     = false;
        SearchEmailBtn.IsEnabled = false;
        SetExportEnabled(false);
        SetStatus($"[{envLabel}] Fetching {label} transactions…");
        SetConnectionStatus(false);

        _transactions.Clear();
        _items.Clear();
        _disbEntries.Clear();
        _rawJsons.Clear();
        _selectedTransaction = null;
        ClearRawJson();
        UpdateSummary();
        ShowItemsPlaceholder(true);

        try
        {
            var environment = IsSandbox ? PayrixEnvironment.Sandbox : PayrixEnvironment.Production;
            var service = new PayrixService(apiKey, environment);

            // ── Phase 1: fetch from Payrix API ───────────────────────────────────
            SetBusyText("🌐  Fetching from Payrix API…");
            var (txns, rawJson, error) = await service.SearchByPaymentCategoryAsync(
                string.IsNullOrEmpty(email) ? null : email, category, limit);

            _rawJsons.Add(rawJson);
            SetRawJson(PrettyPrint(rawJson));

            if (error is not null && txns.Count == 0)
            {
                SetStatus($"[{envLabel}] {error}", error: true);
                return;
            }

            // ── Phase 2: enrich in parallel with live counter ────────────────────
            SetStatus($"[{envLabel}] Loading details for {txns.Count} {label} transaction(s)…");
            SetBusyCount(txns.Count);
            await Task.WhenAll(txns.Select(async txn =>
            {
                await EnrichTransactionAsync(service, txn, envLabel, bulkMode: true);
                await Dispatcher.InvokeAsync(() =>
                {
                    _suppressKpiRefresh = true;
                    _transactions.Add(txn);
                    _suppressKpiRefresh = false;
                });
                IncrementBusyProgress();
            }));

            SortTransactionsByCreated();
            RefreshOverviewKpis();

            TxnIdsBox.Text = string.Join(", ", txns.Select(t => t.Id).Where(id => id is not null));

            UpdateSummary();
            SetConnectionStatus(_transactions.Count > 0);
            SetStatus($"[{envLabel}] Loaded {txns.Count} {label} transaction(s)." +
                      (error is not null ? $"  ⚠ {error}" : ""));

            if (txns.Count > 0)
                ShowToast($"All {txns.Count} {label} transaction(s) fetched — enjoy! 🎉");

            SetExportEnabled(_transactions.Count > 0);

            if (_transactions.Count > 0)
                LoadAllItems();
        }
        catch (Exception ex)
        {
            SetStatus($"Fetch failed: {ex.Message}", error: true);
            WpfMessageBox.Show($"Error fetching {label} transactions:\n\n{ex.Message}",
                "Fetch Error", MessageBoxButton.OK, MessageBoxImage.Error);
        }
        finally
        {
            SetBusy(false);
            FetchAchBtn.IsEnabled    = true;
            FetchCardBtn.IsEnabled   = true;
            FetchBtn.IsEnabled       = true;
            SearchEmailBtn.IsEnabled = true;
        }
    }

