            SetStatus("Local Main DB connection string is empty. Use ⚡ Auto-detect or enter it manually.");
            return;
        }

        FetchIdsByEmailBtn.IsEnabled = false;
        SetStatus($"Looking up AccountID + CompanyID for {email}…");
