            msg('Business text fields filled');

            /* MUI: Industry */
            setTimeout(function(){
                muiSelect('Industry','Professional',function(){
                    /* MUI: TIN Type */
                    setTimeout(function(){
                        muiSelect('TIN Type','EIN',function(){
                            /* Payment method: Customer Enters Payment Online */
                            setTimeout(function(){
                                /* Close any stray dialogs first */
