        RefreshOverviewApiKpis();
    }

    // ── Merchants tab ─────────────────────────────────────────────────────────

    private readonly System.Collections.ObjectModel.ObservableCollection<Models.Merchant> _merchants = [];
    private List<Models.Merchant> _allMerchants    = [];
    private List<Models.Merchant> _filteredMerchants = [];

    // Disbursements pagination
    private List<DisbursementRecord> _allDisbRecords = [];
    private int _dPage     = 1;
    private int _dPageSize = 20;

    private Models.Merchant? _selectedMerchant;
    private string _merchantStatusFilter = "All"; // "All" | "Active" | "Inactive" | "Suspended"

    // Merchant pagination
    private int _mPage     = 1;
    private int _mPageSize = 20;

    // Pinned merchant IDs (persists across re-loads within a session)
    private const string DefaultPinnedMerchantId = "t1_mer_626f798aec3d7dea43bb707";
    private readonly HashSet<string> _pinnedMerchantIds = new(StringComparer.OrdinalIgnoreCase)
        { DefaultPinnedMerchantId };

    // Sort state for Merchants tab
    private string? _mSortColumn    = null;
    private bool    _mSortAscending = true;

    private async void LoadMerchants_Click(object sender, RoutedEventArgs e)
    {
        SetBusy(true);
        var apiKey   = IsSandbox ? SandboxApiKeyBox.Password.Trim() : ProductionApiKeyBox.Password.Trim();
        var envLabel = IsSandbox ? "Sandbox" : "Production";

        if (string.IsNullOrEmpty(apiKey))
        {
            WpfMessageBox.Show($"Enter your {envLabel} API key in the Settings tab first.",
                "Load Merchants", MessageBoxButton.OK, MessageBoxImage.Warning);
            return;
        }

        // Read limit from input (0 = all)
        var limitText = MerchantLimitBox.Text.Trim();
        int merchantLimit = int.TryParse(limitText, out var lv) && lv >= 0 ? lv : 0;

        LoadMerchantsBtn.IsEnabled = false;
        LoadMerchantsBtn.Content   = "⟳  Loading…";
        MerchantEmptyState.Visibility = Visibility.Visible;
        MerchantEmptyText.Text        = merchantLimit == 0
            ? $"Fetching all merchants from {envLabel}…"
            : $"Fetching up to {merchantLimit} merchants from {envLabel}…";
        MerchantList.ItemsSource = null;
        MerchantDetailPanel.Visibility = Visibility.Collapsed;
        MerchantDetailEmpty.Visibility = Visibility.Visible;

        try
        {
            var env     = IsSandbox ? PayrixEnvironment.Sandbox : PayrixEnvironment.Production;
            var service = new PayrixService(apiKey, env);

            var (merchants, _, error) = await service.GetMerchantsAsync(merchantLimit);

            if (error != null)
            {
                MerchantEmptyText.Text = $"Error: {error}";
                WpfMessageBox.Show($"Failed to load merchants:\n\n{error}", "Load Merchants",
                    MessageBoxButton.OK, MessageBoxImage.Error);
                return;
            }

            // Restore pin state from session set
            foreach (var m in merchants)
                m.IsPinned = _pinnedMerchantIds.Contains(m.Id);

            // Ensure default-pinned merchant is in the list (add placeholder if API omitted it)
            if (merchants.All(m => m.Id != DefaultPinnedMerchantId))
            {
                merchants.Insert(0, new Models.Merchant
                {
                    Id       = DefaultPinnedMerchantId,
                    Name     = DefaultPinnedMerchantId,
                    IsPinned = true,
                    Status   = 0,
                });
            }

            _allMerchants = merchants;

            // Enrich entity names and Core DB link status concurrently in background
            var merchantCoreConnStr = ActiveMainDbConnectionString();
            var merchantSnapshot    = merchants.ToList(); // capture before async

            // CORE check — runs immediately, independent of the slow entity-name API loop
            if (!string.IsNullOrWhiteSpace(merchantCoreConnStr))
            {
                _ = Task.Run(async () =>
                {
                    var (linked, coreErr) = await Services.HostDbService
                        .GetLinkedMerchantIdsAsync(merchantCoreConnStr, merchantSnapshot.Select(m => m.Id))
                        .ConfigureAwait(false);
                    await Dispatcher.InvokeAsync(() =>
                    {
                        if (coreErr != null)
                            SetStatus($"⚠ Core link check: {coreErr}");
                        foreach (var m in merchantSnapshot)
                            m.LinkedToCore = linked.Contains(m.Id);
                    });
                });
            }

            // Entity-name enrichment — runs separately so it can't block the CORE check
            _ = Task.Run(async () =>
            {
                foreach (var m in merchantSnapshot.Where(m => !string.IsNullOrEmpty(m.Entity) && m.EntityName is null))
                {
                    var name = await service.GetEntityNameAsync(m.Entity!).ConfigureAwait(false);
                    if (name is not null)
                        await Dispatcher.InvokeAsync(() => m.EntityName = name);
                }
            });

            _mSortColumn = null;
            ResetMSortArrows();
            ApplyMerchantFilter(MerchantSearchBox.Text);
            OnPropertyChanged(nameof(DashActiveMerchants));

            MerchantSubtitle.Text = $"{merchants.Count} merchant(s) in {envLabel}";
            MerchantEnvLabel.Text = envLabel;

            if (merchants.Count == 0)
                MerchantEmptyText.Text = $"No merchants found in {envLabel}.";
            else
                MerchantEmptyState.Visibility = Visibility.Collapsed;
        }
        catch (Exception ex)
        {
            MerchantEmptyText.Text = $"Error: {ex.Message}";
        }
        finally
        {
            SetBusy(false);
            LoadMerchantsBtn.IsEnabled = true;
            LoadMerchantsBtn.Content   = "⟳  Load Merchants";
        }
    }

    private void ApplyMerchantFilter(string? query)
    {
        // Status filter
        var byStatus = _merchantStatusFilter switch
        {
            "Submitted" => _allMerchants.Where(m => m.Status == 1).ToList(),
            "Active"    => _allMerchants.Where(m => m.Status == 2).ToList(),
            "Inactive"  => _allMerchants.Where(m => m.Status == 3).ToList(),
            "Suspended" => _allMerchants.Where(m => m.Status == 4).ToList(),
            "Boarded"   => _allMerchants.Where(m => m.Status == 2)          // Active/Boarded = status 2
                                        .OrderByDescending(m => m.Boarded ?? m.Created)
                                        .Take(20).ToList(),
            _           => _allMerchants.ToList()
        };

        // Text search
        var searched = string.IsNullOrWhiteSpace(query)
            ? byStatus
            : byStatus.Where(m =>
                m.Name.Contains(query, StringComparison.OrdinalIgnoreCase) ||
                m.Id.Contains(query, StringComparison.OrdinalIgnoreCase) ||
                (m.Descriptor?.Contains(query,   StringComparison.OrdinalIgnoreCase) ?? false) ||
                (m.Email?.Contains(query,        StringComparison.OrdinalIgnoreCase) ?? false) ||
                (m.Entity?.Contains(query,       StringComparison.OrdinalIgnoreCase) ?? false) ||
                (m.EntityName?.Contains(query,   StringComparison.OrdinalIgnoreCase) ?? false) ||
                (m.Dba?.Contains(query,          StringComparison.OrdinalIgnoreCase) ?? false)).ToList();

        // Sort — pinned always at top regardless
        var pinned = searched.Where(m =>  m.IsPinned).ToList();
        var rest   = searched.Where(m => !m.IsPinned).ToList();

        IEnumerable<Models.Merchant> sorted = _mSortColumn switch
        {
            "DisplayName" => _mSortAscending
                ? rest.OrderBy(m => m.DisplayName, StringComparer.OrdinalIgnoreCase)
                : rest.OrderByDescending(m => m.DisplayName, StringComparer.OrdinalIgnoreCase),
            "Descriptor"  => _mSortAscending
                ? rest.OrderBy(m => m.Descriptor ?? "", StringComparer.OrdinalIgnoreCase)
                : rest.OrderByDescending(m => m.Descriptor ?? "", StringComparer.OrdinalIgnoreCase),
            "Status"      => _mSortAscending ? rest.OrderBy(m => m.Status)            : rest.OrderByDescending(m => m.Status),
            "KycCode"     => _mSortAscending ? rest.OrderBy(m => m.Kyc?.Status ?? 99) : rest.OrderByDescending(m => m.Kyc?.Status ?? 99),
            "Created"     => _mSortAscending ? rest.OrderBy(m => m.Created)           : rest.OrderByDescending(m => m.Created),
            _             => rest
        };

        _filteredMerchants = pinned.Concat(sorted).ToList();
        _mPage = 1;
        RefreshMerchantPage();
    }

    private void RefreshMerchantPage()
    {
        if (MerchantPagingText is null || MerchantPageNumText is null ||
            MerchantPrevPageBtn is null || MerchantNextPageBtn is null) return;

        var total = _filteredMerchants.Count;
        var start = (_mPage - 1) * _mPageSize;
        var page  = _filteredMerchants.Skip(start).Take(_mPageSize).ToList();
        var end   = start + page.Count;

        MerchantList.ItemsSource = page;
        // Sync column widths to freshly created rows (hidden columns, drag-resized widths)
        Dispatcher.InvokeAsync(() =>
            SyncColumns(MerchantHeaderGrid, MerchantList, _merchHeaderDataCols),
            System.Windows.Threading.DispatcherPriority.Loaded);

        MerchantEmptyState.Visibility = total == 0 && _allMerchants.Count > 0
            ? Visibility.Visible : Visibility.Collapsed;
        if (total == 0 && _allMerchants.Count > 0)
            MerchantEmptyText.Text = _merchantStatusFilter == "All"
                ? "No merchants match your search."
                : $"No {_merchantStatusFilter.ToLower()} merchants found.";

        MerchantPagingText.Text = total == 0
            ? "No merchants loaded"
            : $"Showing {start + 1} to {end} of {total} merchants";
        MerchantPageNumText.Text    = _mPage.ToString();
        MerchantPrevPageBtn.IsEnabled = _mPage > 1;
        MerchantNextPageBtn.IsEnabled = end < total;
    }

    private void MerchantPageSizeBox_SelectionChanged(object sender, System.Windows.Controls.SelectionChangedEventArgs e)
    {
        _mPageSize = MerchantPageSizeBox.SelectedIndex switch
        {
            1 => 50,
            2 => 100,
            _ => 20
        };
        _mPage = 1;
        RefreshMerchantPage();
    }

    private void MerchantPrevPageBtn_Click(object sender, RoutedEventArgs e)
    {
        if (_mPage > 1) { _mPage--; RefreshMerchantPage(); }
    }

    private void MerchantNextPageBtn_Click(object sender, RoutedEventArgs e)
    {
        var maxPage = (int)Math.Ceiling(_filteredMerchants.Count / (double)_mPageSize);
        if (_mPage < maxPage) { _mPage++; RefreshMerchantPage(); }
    }

    // ── Disbursements pagination ──────────────────────────────────────────────

    private void RefreshDisbPage()
    {
        if (DisbPagingText is null || DisbPageNumText is null ||
            DisbPrevPageBtn is null || DisbNextPageBtn is null) return;

        var total = _allDisbRecords.Count;
        var start = (_dPage - 1) * _dPageSize;
        var page  = _allDisbRecords.Skip(start).Take(_dPageSize).ToList();
        var end   = start + page.Count;

        DisbGrid.ItemsSource = page;

        DisbEmptyState.Visibility = total == 0 ? Visibility.Visible : Visibility.Collapsed;
        DisbGrid.Visibility       = total  > 0 ? Visibility.Visible : Visibility.Collapsed;

        DisbPagingText.Text    = total == 0
            ? "No disbursements loaded"
            : $"Showing {start + 1} to {end} of {total} disbursements";
        DisbPageNumText.Text      = _dPage.ToString();
        DisbPrevPageBtn.IsEnabled = _dPage > 1;
        DisbNextPageBtn.IsEnabled = end < total;
    }

