    private void AccSplitter_DragDelta(object sender, System.Windows.Controls.Primitives.DragDeltaEventArgs e)
        => SyncColumns(AccHeaderGrid, AccountMerchantList, new[] { 0, 2, 4, 6, 8, 10, 12, 14, 16 });

    private void MerchantSplitter_DragDelta(object sender, System.Windows.Controls.Primitives.DragDeltaEventArgs e)
        => SyncColumns(MerchantHeaderGrid, MerchantList, new[] { 0, 1, 3, 5, 7, 9, 11, 13, 15 });

    private void SyncColumns(System.Windows.Controls.Grid headerGrid, System.Windows.Controls.ItemsControl list, int[] headerDataCols)
    {
        // Read Width.Value (set synchronously by GridSplitter) rather than ActualWidth (stale until layout).
        // After any drag the GridSplitter converts star columns to absolute, so Width.Value is correct.
        // Star columns that haven't been dragged yet stay as star in the rows (fills remaining space).
        var panel = FindFirstVisualChild<System.Windows.Controls.StackPanel>(list);
        if (panel == null) return;
        foreach (UIElement child in panel.Children)
        {
            var grid = FindFirstVisualChild<System.Windows.Controls.Grid>(child);
            if (grid == null) continue;
            foreach (int hIdx in headerDataCols)
            {
                if (hIdx >= headerGrid.ColumnDefinitions.Count || hIdx >= grid.ColumnDefinitions.Count) continue;
                var hcol = headerGrid.ColumnDefinitions[hIdx];
                if (hcol.Width.IsStar) continue;        // let the row's star column fill naturally
                double px = hcol.Width.IsAbsolute ? hcol.Width.Value : hcol.ActualWidth;
                grid.ColumnDefinitions[hIdx].Width = new GridLength(px);  // allow 0 (hidden column)
            }
        }
    }

    private static T? FindFirstVisualChild<T>(DependencyObject parent) where T : DependencyObject
    {
        for (int i = 0; i < System.Windows.Media.VisualTreeHelper.GetChildrenCount(parent); i++)
        {
            var child = System.Windows.Media.VisualTreeHelper.GetChild(parent, i);
            if (child is T t) return t;
            var found = FindFirstVisualChild<T>(child);
            if (found != null) return found;
        }
        return null;
    }

