    private async void AccDeleteSelected_Click(object sender, RoutedEventArgs e)
    {
        var targets = _allAccountRows.Where(r => r.IsSelected).ToList();
        if (targets.Count == 0) return;
        if (!IosAlertDialog.Show(
                title:       "Bulk Delete Accounts",
                message:     $"Delete {targets.Count} selected merchant account(s) from Payrix and remove their Core DB links?\n\nThis cannot be undone.",
                actionLabel: "Delete",
                destructive: true,
                owner:       this)) return;

        AccDeleteSelectedBtn.IsEnabled = false;
        SetBusy(true);
        var apiKey  = IsSandbox ? SandboxApiKeyBox.Password.Trim() : ProductionApiKeyBox.Password.Trim();
        var env     = IsSandbox ? PayrixEnvironment.Sandbox : PayrixEnvironment.Production;
        var svc     = new PayrixService(apiKey, env);
        var coreStr = ActiveMainDbConnectionString();

        int ok = 0, fail = 0, hasTxn = 0;
        foreach (var row in targets)
        {
            var (success, _, err) = await svc.DeleteMerchantAsync(row.MerchantId).ConfigureAwait(false);
            if (success)
            {
                ok++;
                if (!string.IsNullOrWhiteSpace(coreStr))
                    await Services.HostDbService.DeleteThirdPartySettingAsync(coreStr, row.MerchantId).ConfigureAwait(false);
                await Dispatcher.InvokeAsync(() => _allAccountRows.Remove(row));
            }
            else if (err != null && (err.Contains("code 17") || err.Contains("Could not delete")))
                hasTxn++;
            else
                fail++;
        }
        await Dispatcher.InvokeAsync(() =>
        {
            ApplyAccSort();
            SetBusy(false);
            var parts = new List<string>();
            if (ok > 0)    parts.Add($"{ok} deleted");
            if (hasTxn > 0) parts.Add($"{hasTxn} skipped (has transactions — deactivate instead)");
            if (fail > 0)  parts.Add($"{fail} failed");
            SetStatus($"Bulk delete: {string.Join(", ", parts)}.");
            AccSelectAllChk.IsChecked       = false;
            AccDeleteSelectedBtn.Visibility  = Visibility.Collapsed;
            AccDeleteSelectedBtn.IsEnabled   = true;
        });
    }

