    private void AccColCheck_Click(object sender, RoutedEventArgs e)
    {
        if (sender is not System.Windows.Controls.CheckBox cb || cb.Tag is not string tag) return;
        var parts = tag.Split(':');
        if (parts.Length < 3) return;
        int headerCol = int.Parse(parts[0]), defW = int.Parse(parts[1]), splitterCol = int.Parse(parts[2]);
        bool show = cb.IsChecked == true;
        AccHeaderGrid.ColumnDefinitions[headerCol].Width  = show ? new GridLength(defW) : new GridLength(0);
        AccHeaderGrid.ColumnDefinitions[splitterCol].Width = show ? new GridLength(4)   : new GridLength(0);
        // Rows now mirror the header column structure — use the same indices directly
        var aPanel = FindFirstVisualChild<System.Windows.Controls.StackPanel>(AccountMerchantList);
        if (aPanel != null)
            foreach (UIElement child in aPanel.Children)
            {
                var grid = FindFirstVisualChild<System.Windows.Controls.Grid>(child);
                if (grid == null) continue;
                if (headerCol  < grid.ColumnDefinitions.Count)
                    grid.ColumnDefinitions[headerCol].Width  = show ? new GridLength(defW) : new GridLength(0);
                if (splitterCol < grid.ColumnDefinitions.Count)
                    grid.ColumnDefinitions[splitterCol].Width = show ? new GridLength(4)   : new GridLength(0);
            }
        SaveColumnChooserState();
    }

