    // ── Column chooser persistence ────────────────────────────────────────────

    private static IEnumerable<System.Windows.Controls.CheckBox> GetPopupCheckBoxes(System.Windows.Controls.Primitives.Popup popup)
    {
        var queue = new Queue<DependencyObject>();
        queue.Enqueue(popup);
        while (queue.Count > 0)
        {
            var node = queue.Dequeue();
            if (node is System.Windows.Controls.CheckBox cb) yield return cb;
            foreach (var child in LogicalTreeHelper.GetChildren(node).OfType<DependencyObject>())
                queue.Enqueue(child);
        }
    }

    private void SaveColumnChooserState()
    {
        if (!_isInitialized) return;
        var s = Services.SettingsService.Load();
        s.AccHiddenColumns = GetPopupCheckBoxes(AccColChooserPopup)
            .Where(cb => cb.Tag is string t && t.Contains(':') && cb.IsChecked != true)
            .Select(cb => int.Parse(((string)cb.Tag!).Split(':')[0]))
            .ToList();
        s.MerchHiddenColumns = GetPopupCheckBoxes(MerchColChooserPopup)
            .Where(cb => cb.Tag is string t && t.Contains(':') && cb.IsChecked != true)
            .Select(cb => int.Parse(((string)cb.Tag!).Split(':')[0]))
            .ToList();
        Services.SettingsService.Save(s);
    }

    private void ApplyColumnChooserState(Models.AppSettings s)
    {
        // Apply to Accounts checkboxes + header columns
        foreach (var cb in GetPopupCheckBoxes(AccColChooserPopup))
        {
            if (cb.Tag is not string tag) continue;
            var parts = tag.Split(':');
            if (parts.Length < 3) continue;
            int headerCol = int.Parse(parts[0]), defW = int.Parse(parts[1]), splitterCol = int.Parse(parts[2]);
            bool hidden = s.AccHiddenColumns.Contains(headerCol);
            cb.IsChecked = !hidden;
            AccHeaderGrid.ColumnDefinitions[headerCol].Width  = hidden ? new GridLength(0) : new GridLength(defW);
            AccHeaderGrid.ColumnDefinitions[splitterCol].Width = hidden ? new GridLength(0) : new GridLength(4);
        }
        // Apply to Merchants checkboxes + header columns
        foreach (var cb in GetPopupCheckBoxes(MerchColChooserPopup))
        {
            if (cb.Tag is not string tag) continue;
            var parts = tag.Split(':');
            if (parts.Length < 3) continue;
            int headerCol = int.Parse(parts[0]), defW = int.Parse(parts[1]), splitterCol = int.Parse(parts[2]);
            bool hidden = s.MerchHiddenColumns.Contains(headerCol);
            cb.IsChecked = !hidden;
            MerchantHeaderGrid.ColumnDefinitions[headerCol].Width  = hidden ? new GridLength(0) : new GridLength(defW);
            MerchantHeaderGrid.ColumnDefinitions[splitterCol].Width = hidden ? new GridLength(0) : new GridLength(4);
        }
    }

    private async void DeleteTransaction_Click(object sender, RoutedEventArgs e)
    {
        e.Handled = true;
        var txnId = (sender as System.Windows.Controls.Button)?.Tag?.ToString();
        if (string.IsNullOrEmpty(txnId)) return;

        var txn   = _transactions.FirstOrDefault(t => t.Id == txnId);
        var label = txnId[..Math.Min(txnId.Length, 20)];

        bool confirm = IosAlertDialog.IsDark = _isDarkMode;
        confirm = IosAlertDialog.Show(
            title:       "Delete Transaction",
            message:     $"This will permanently delete transaction \"{label}\" from Payrix.\n\nThis cannot be undone.",
            actionLabel: "Delete",
            destructive: true,
            owner:       this);
        if (!confirm) return;

        SetBusy(true);
        SetStatus("Deleting transaction…");

        try
        {
            var apiKey = IsSandbox ? SandboxApiKeyBox.Password.Trim() : ProductionApiKeyBox.Password.Trim();
            var env    = IsSandbox ? PayrixEnvironment.Sandbox : PayrixEnvironment.Production;
            var svc    = new PayrixService(apiKey, env);

            var (ok, rawJson, err) = await svc.DeleteTransactionAsync(txnId);
            if (!ok)
            {
                SetStatus($"⚠  Delete failed: {err}");
                WpfMessageBox.Show($"Payrix error: {err}", "Delete Failed",
                    MessageBoxButton.OK, MessageBoxImage.Error);
                return;
            }

            if (txn != null) _transactions.Remove(txn);
            SetStatus($"✅  Transaction \"{label}\" deleted from Payrix.");
        }
        finally
        {
            SetBusy(false);
        }
    }

    private async void DeleteMerchant_Click(object sender, RoutedEventArgs e)
    {
        if (_selectedMerchant == null) return;
        var m = _selectedMerchant;

        bool confirm = IosAlertDialog.IsDark = _isDarkMode;
        confirm = IosAlertDialog.Show(
            title:       "Delete Merchant",
            message:     $"This will permanently delete {m.ShortId} from Payrix and remove its Core DB link.\n\nThis cannot be undone.",
            actionLabel: "Delete",
            destructive: true,
            owner:       this);
        if (!confirm) return;

        MDetailDeleteBtn.IsEnabled = false;
        MDetailDeleteBtn.Content   = "Deleting…";
        SetBusy(true);

        try
        {
            var apiKey = IsSandbox ? SandboxApiKeyBox.Password.Trim() : ProductionApiKeyBox.Password.Trim();
            var env    = IsSandbox ? PayrixEnvironment.Sandbox : PayrixEnvironment.Production;
            var svc    = new PayrixService(apiKey, env);

            // 1. Delete from Payrix
            var (ok, rawJson, err) = await svc.DeleteMerchantAsync(m.Id);
            SetRawJson(PrettyPrint(rawJson));

            if (!ok)
            {
                SetStatus($"⚠  Delete failed: {err}");
                // Payrix code 17 = merchant has transactions — cannot hard-delete, offer deactivate instead
                bool hasTransactions = err != null && (err.Contains("code 17") || err.Contains("Could not delete"));
                if (hasTransactions)
                {
                    SetBusy(false);
                    MDetailDeleteBtn.IsEnabled = true;
                    MDetailDeleteBtn.Content   = "🗑 Delete";
                    bool deactivate = IosAlertDialog.Show(
                        title:       "Cannot Delete — Has Transactions",
                        message:     $"Payrix cannot delete {m.ShortId} because it has existing transactions.\n\nWould you like to deactivate it instead?",
                        actionLabel: "Deactivate",
                        destructive: true,
                        owner:       this);
                    if (deactivate)
                        await DoToggleMerchantStatus(m);
                    return;
                }
                WpfMessageBox.Show($"Payrix error: {err}\n\nSee Raw JSON tab.", "Delete Failed",
                    MessageBoxButton.OK, MessageBoxImage.Error);
                return;
            }

            // 2. Remove Core DB link
            var connStr = ActiveMainDbConnectionString();
            if (!string.IsNullOrWhiteSpace(connStr))
            {
                var (_, dbErr) = await Services.HostDbService.DeleteThirdPartySettingAsync(connStr, m.Id);
                if (dbErr != null)
                    SetStatus($"✅  Payrix merchant deleted — Core DB cleanup warning: {dbErr}");
                else
                    SetStatus($"✅  Merchant {m.ShortId} deleted from Payrix and Core DB.");
            }
            else
            {
                SetStatus($"✅  Merchant {m.ShortId} deleted from Payrix (no DB connection for Core cleanup).");
            }

            // 3. Remove from local list and collapse detail panel
            _allMerchants.Remove(m);
            _selectedMerchant = null;
            MerchantDetailPanel.Visibility = Visibility.Collapsed;
            MerchantDetailEmpty.Visibility = Visibility.Visible;
            ApplyMerchantFilter(MerchantSearchBox?.Text);
        }
        finally
        {
            MDetailDeleteBtn.IsEnabled = true;
            MDetailDeleteBtn.Content   = "🗑 Delete";
            SetBusy(false);
        }
    }

    // ── Delete account — from Accounts tab row ────────────────────────────────

    private async void DeleteAccount_Click(object sender, RoutedEventArgs e)
    {
        e.Handled = true;
        var merchantId = (sender as System.Windows.Controls.Button)?.Tag?.ToString();
        if (string.IsNullOrEmpty(merchantId)) return;

        var row = _allAccountRows.FirstOrDefault(r => r.MerchantId == merchantId);
        var label = row?.DisplayName ?? merchantId[..Math.Min(merchantId.Length, 20)];

        bool confirm = IosAlertDialog.IsDark = _isDarkMode;
        confirm = IosAlertDialog.Show(
            title:       "Delete Account",
            message:     $"This will delete the Payrix merchant for \"{label}\" and remove its Core DB link.\n\nThis cannot be undone.",
            actionLabel: "Delete",
            destructive: true,
            owner:       this);
        if (!confirm) return;

        SetBusy(true);
        SetStatus("Deleting merchant and Core DB link…");

        try
        {
            var apiKey = IsSandbox ? SandboxApiKeyBox.Password.Trim() : ProductionApiKeyBox.Password.Trim();
            var env    = IsSandbox ? PayrixEnvironment.Sandbox : PayrixEnvironment.Production;
            var svc    = new PayrixService(apiKey, env);

            // 1. Delete from Payrix
            var (ok, rawJson, err) = await svc.DeleteMerchantAsync(merchantId);
            if (!ok)
            {
                SetStatus($"⚠  Delete failed: {err}");
                WpfMessageBox.Show($"Payrix error: {err}", "Delete Failed",
                    MessageBoxButton.OK, MessageBoxImage.Error);
                return;
            }

            // 2. Remove Core DB link
            var connStr = ActiveMainDbConnectionString();
            if (!string.IsNullOrWhiteSpace(connStr))
                await Services.HostDbService.DeleteThirdPartySettingAsync(connStr, merchantId);

            // 3. Remove from local list and refresh UI
            if (row != null) _allAccountRows.Remove(row);
            ApplyAccSort();
            SetStatus($"✅  Account \"{label}\" deleted from Payrix and Core DB.");
        }
        finally
        {
            SetBusy(false);
        }
    }

    // ── Activate / Deactivate — from the detail panel button ─────────────────

    private async void ToggleMerchantDetail_Click(object sender, RoutedEventArgs e)
    {
        SetBusy(true);
        if (_selectedMerchant == null) return;
        await DoToggleMerchantStatus(_selectedMerchant);
    }

    private async System.Threading.Tasks.Task DoToggleMerchantStatus(Models.Merchant m)
    {
        // Payrix status: 0=Created, 1=Submitted, 2=Active/Boarded, 3=Inactive, 4=Suspended
        // Deactivate: Active(2) → Inactive(3).  Activate: anything else → Boarded(2).
        var newStatus = m.IsLive ? 3 : 2;
        var verb      = newStatus == 2 ? "Activate" : "Deactivate";

        IosAlertDialog.IsDark = _isDarkMode;
        bool confirm = IosAlertDialog.Show(
            title:       $"{verb} Merchant",
            message:     m.ShortId,
            actionLabel: verb,
            destructive: newStatus == 3,   // Deactivate is destructive (red button)
            owner:       this);
        if (!confirm) return;

        m.ToggleBusy = true;

        // Sync detail panel button if this merchant is currently open
        if (_selectedMerchant?.Id == m.Id)
        {
            MDetailToggleBtn.IsEnabled = false;
            MDetailToggleBtn.Content   = "Updating…";
        }

        try
        {
            var apiKey = IsSandbox ? SandboxApiKeyBox.Password.Trim() : ProductionApiKeyBox.Password.Trim();
            var env    = IsSandbox ? PayrixEnvironment.Sandbox : PayrixEnvironment.Production;
            var svc    = new PayrixService(apiKey, env);

            SetStatus("Updating merchant status…");
            var (updated, rawJson, err) = await svc.UpdateMerchantStatusAsync(m.Id, newStatus);

            if (err != null)
            {
                // Show raw response in Raw JSON tab for diagnosis
                SetRawJson(PrettyPrint(rawJson));
                SetStatus($"⚠  Activate failed: {err}  — see Raw JSON tab for details");
                var detail = $"Payrix error: {err}\n\nFull response shown in Raw JSON tab.";
                WpfMessageBox.Show(detail, $"Could Not {verb} Merchant",
                    MessageBoxButton.OK, MessageBoxImage.Error);
                return;
            }

            m.Status = updated?.Status ?? newStatus;

            // Refresh the detail panel badges if this merchant is open
            if (_selectedMerchant?.Id == m.Id)
            {
                var bc = new System.Windows.Media.BrushConverter();
                System.Windows.Media.Brush HexBrush(string hex) =>
                    (System.Windows.Media.Brush?)bc.ConvertFromString(hex)
                    ?? System.Windows.Media.Brushes.Transparent;

                MDetailStatus.Text            = m.StatusLabel;
                MDetailStatus.Foreground      = HexBrush(m.StatusColor);
                MDetailStatusBadge.Background = HexBrush(m.StatusBg);
                MDetailToggleBtn.Content    = m.ToggleStatusLabel;
                MDetailToggleBtn.Background = m.IsLive
                    ? new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromRgb(220,  38,  38))  // red = Deactivate
                    : new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromRgb( 22, 163,  74)); // green = Activate
            }

            OnPropertyChanged(nameof(DashActiveMerchants));
            SetStatus($"{m.DisplayName} → {m.StatusLabel}");
        }
        catch (Exception ex)
        {
            SetStatus($"⚠ {ex.Message}");
        }
        finally
        {
            m.ToggleBusy = false;
            if (_selectedMerchant?.Id == m.Id)
                MDetailToggleBtn.IsEnabled = true;
        }
    }

    // ── Expand / Collapse All ─────────────────────────────────────────────────

    private void CollapseAll_Click(object sender, RoutedEventArgs e)
    {
        foreach (var col in _collections)
        {
            col.Expanded = false;
            // Mark all categories collapsed without touching GroupedRequests (avoids rebuild)
            foreach (var cat in col.Requests.Select(r => r.Category).Distinct())
                col.SetGroupExpanded(cat, false);
            col.RaiseGroupedRequestsChanged();
        }
    }

    private void ExpandAll_Click(object sender, RoutedEventArgs e)
    {
        foreach (var col in _collections)
        {
            col.Expanded = true;
            foreach (var cat in col.Requests.Select(r => r.Category).Distinct())
                col.SetGroupExpanded(cat, true);
            col.RaiseGroupedRequestsChanged();
        }
    }

    // ── Recent requests panel ────────────────────────────────────────────────

    private const int RecentMaxItems = 15;
    private bool _recentExpanded = true;

    /// <summary>
    /// Reload recent entries from disk and refresh the sidebar panel.
    /// Call after every send and on window load.
    /// </summary>
    private void RefreshRecentPanel()
    {
        var entries = Services.RequestLogService.Load()
                              .Take(RecentMaxItems)
                              .ToList();

        RecentList.ItemsSource    = entries;
        RecentCountLabel.Text     = entries.Count.ToString();
        RecentClearBtn.Visibility = entries.Count > 0
            ? Visibility.Visible : Visibility.Collapsed;

        // Show/hide the whole panel body based on expand state
        RecentList.Visibility = _recentExpanded ? Visibility.Visible : Visibility.Collapsed;
        RecentChevron.Text    = _recentExpanded ? "▼" : "▶";

        // Keep Overview API stats in sync
        OnPropertyChanged(nameof(OverviewRecentCount));
    }

    private void RecentHeader_Click(object sender, System.Windows.Input.MouseButtonEventArgs e)
    {
        _recentExpanded = !_recentExpanded;
        RecentList.Visibility = _recentExpanded ? Visibility.Visible : Visibility.Collapsed;
        RecentChevron.Text    = _recentExpanded ? "▼" : "▶";
    }

    private void RecentClear_Click(object sender, RoutedEventArgs e)
    {
        Services.RequestLogService.Save([]);
        RefreshRecentPanel();
        e.Handled = true;   // don't bubble to RecentHeader_Click
    }

    private void RecentItem_Click(object sender, System.Windows.Input.MouseButtonEventArgs e)
    {
        if (sender is System.Windows.Controls.Border b &&
            b.Tag is Models.RequestLogEntry entry)
        {
            // Populate URL
            _suppressUrlSave = true;
            HttpUrlBox.Text  = entry.Url;
            _suppressUrlSave = false;

            // Method
            var methodItem = HttpMethodBox.Items
                .Cast<System.Windows.Controls.ComboBoxItem>()
                .FirstOrDefault(i => i.Content?.ToString() == entry.Method);
            if (methodItem != null) HttpMethodBox.SelectedItem = methodItem;

            // Auth — restore token if it was a bearer call
            if (entry.AuthType == "Bearer Token" && !string.IsNullOrEmpty(entry.Token))
            {
                var bearerItem = HttpAuthTypeBox.Items
                    .Cast<System.Windows.Controls.ComboBoxItem>()
                    .FirstOrDefault(i => i.Content?.ToString() == "Bearer Token");
                if (bearerItem != null) HttpAuthTypeBox.SelectedItem = bearerItem;
                AuthBearerTokenBox.Text = entry.Token;
            }

            HttpUrlBox.Focus();
        }
    }

    // ── Collection Search ─────────────────────────────────────────────────────

    private void CollectionSearch_TextChanged(object sender, System.Windows.Controls.TextChangedEventArgs e)
    {
        var query = CollectionSearchBox.Text?.Trim() ?? "";

        // Show/hide clear button
        CollectionSearchClearBtn.Visibility = string.IsNullOrEmpty(query)
            ? Visibility.Collapsed : Visibility.Visible;

        ApplyCollectionSearch(query);
    }

    private void CollectionSearchClear_Click(object sender, RoutedEventArgs e)
    {
        CollectionSearchBox.Text = "";
        CollectionSearchBox.Focus();
    }

    /// <summary>
    /// Filters the sidebar to show only collections/requests that match <paramref name="query"/>.
    /// Matching is case-insensitive against Name, Method, and URL.
    /// When query is empty, restores the normal _collections source.
    /// </summary>
    private void ApplyCollectionSearch(string query)
    {
        if (string.IsNullOrEmpty(query))
        {
            CollectionsPanel.ItemsSource = _collections;
            return;
        }

        var q = query.ToLowerInvariant();

        // Build a temporary filtered list — shallow-clone collections with only matching requests
        var filtered = new System.Collections.ObjectModel.ObservableCollection<Models.HttpCollection>();

        foreach (var col in _collections)
        {
            var matchingRequests = col.Requests
                .Where(r => r.Name.ToLowerInvariant().Contains(q)
                         || r.Method.ToLowerInvariant().Contains(q)
                         || r.Url.ToLowerInvariant().Contains(q))
                .ToList();

            if (matchingRequests.Count == 0) continue;

            // Clone the collection shell with only matching requests, always expanded
            var clone = new Models.HttpCollection
            {
                Id       = col.Id,
                Name     = col.Name,
                Expanded = true,
            };
            foreach (var r in matchingRequests)
                clone.Requests.Add(r);

            filtered.Add(clone);
        }

        CollectionsPanel.ItemsSource = filtered;
    }

